import{$ as e,A as t,B as n,V as r}from"./chunks/framework.6NwDR3kH.js";var i=JSON.parse(`{"title":"XX启动！但是单机版","description":"","frontmatter":{},"headers":[],"relativePath":"ccc/游戏/ys.md","filePath":"ccc/游戏/ys.md"}`),a={name:`ccc/游戏/ys.md`};function o(t,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[r(`<h1 id="xx启动-但是单机版" tabindex="-1">XX启动！但是单机版 <a class="header-anchor" href="#xx启动-但是单机版" aria-label="Permalink to “XX启动！但是单机版”">​</a></h1><p>22年泄露，可完整体验3.2，包括任务。既所谓真端。</p><p><a href="https://github.com/Grasscutters/Grasscutter" target="_blank" rel="noreferrer">网友开发的服务端</a>，能支持新版本，但是没任务，刷怪要控制台。<a href="https://forum.ragezone.com/community/genshin-impact.1044/" target="_blank" rel="noreferrer">论坛</a>；</p><p>本文旨在介绍virtualbox虚拟机软件和linux操作系统的简单用法，恰好以某二次元游戏的服务端为例。</p><h2 id="傻瓜整合包" tabindex="-1">傻瓜整合包 <a class="header-anchor" href="#傻瓜整合包" aria-label="Permalink to “傻瓜整合包”">​</a></h2><p>vmware一键导入即可运行。</p><p><a href="magnet:?xt=urn:btih:7XED5A4UY3NZTDOE6IH5PWOYTJLUBGAU&amp;xt=urn:btmh:122061430fc319c529ff6e0ba427a6497f60392a5fc42c98cecddfc54606d5ff0507&amp;dn=%E5%8E%9F%E7%A5%9E3.2%E7%A6%BB%E7%BA%BF%E7%89%88.%E7%9C%9F%E7%AB%AF.%E6%95%B4%E5%90%88%E5%8C%85.%E8%99%9A%E6%8B%9F%E6%9C%BA%E9%95%9C%E5%83%8F.Genshin%20Impact%20Offline3.2.VM%20image&amp;tr=http%3A%2F%2Ftracker1.itzmx.com%3A8080%2Fannounce&amp;tr=http%3A%2F%2Ftracker2.itzmx.com%3A6961%2Fannounce&amp;tr=http%3A%2F%2Ftracker3.itzmx.com%3A6961%2Fannounce&amp;tr=http%3A%2F%2Ftracker4.itzmx.com%3A2710%2Fannounce&amp;tr=udp%3A%2F%2Ftracker1.itzmx.com%3A8080%2Fannounce&amp;tr=udp%3A%2F%2Ftracker2.itzmx.com%3A6961%2Fannounce&amp;tr=udp%3A%2F%2Ftracker3.itzmx.com%3A6961%2Fannounce&amp;tr=udp%3A%2F%2Ftracker4.itzmx.com%3A2710%2Fannounce&amp;tr=http%3A%2F%2Ftracker.opentrackr.org%3A1337%2Fannounce&amp;tr=udp%3A%2F%2Ftracker.opentrackr.org%3A1337%2Fannounce&amp;tr=https%3A%2F%2Ftracker1.ctix.cn%2Fannounce&amp;tr=udp%3A%2F%2Fopen.demonii.com%3A1337%2Fannounce&amp;tr=https%3A%2F%2Ftracker.loligirl.cn%2Fannounce&amp;tr=udp%3A%2F%2Fopen.stealth.si%3A80%2Fannounce&amp;tr=udp%3A%2F%2Ftracker.torrent.eu.org%3A451%2Fannounce&amp;tr=udp%3A%2F%2Fexplodie.org%3A6969%2Fannounce&amp;tr=udp%3A%2F%2Fexodus.desync.com%3A6969%2Fannounce&amp;tr=https%3A%2F%2Ftracker.tamersunion.org%2Fannounce&amp;tr=https%3A%2F%2Ftracker.renfei.net%2Fannounce&amp;tr=http%3A%2F%2Ftracker.renfei.net%3A8080%2Fannounce&amp;tr=udp%3A%2F%2Fttk2.nbaonlineservice.com%3A6969%2Fannounce&amp;tr=udp%3A%2F%2Ftracker.tryhackx.org%3A6969%2Fannounce&amp;tr=udp%3A%2F%2Ftracker.publictracker.xyz%3A6969%2Fannounce&amp;tr=udp%3A%2F%2Ftracker.moeking.me%3A6969%2Fannounce&amp;tr=udp%3A%2F%2Ftracker.dump.cl%3A6969%2Fannounce&amp;tr=udp%3A%2F%2Ftracker.bittor.pw%3A1337%2Fannounce&amp;tr=udp%3A%2F%2Ftracker.0x7c0.com%3A6969%2Fannounce&amp;tr=udp%3A%2F%2Frun.publictracker.xyz%3A6969%2Fannounce&amp;tr=udp%3A%2F%2Fp2p.publictracker.xyz%3A6969%2Fannounce&amp;xl=87343038446" target="_blank" rel="noreferrer">下载磁力链接</a></p><h2 id="docker" tabindex="-1">docker <a class="header-anchor" href="#docker" aria-label="Permalink to “docker”">​</a></h2><p>docker默认3.2版本，可以通过替换文件跑起3.4，没开发完，有缺失。</p><p>至少分配给虚拟机14g内存，小内存可以尝试安装linux系统时分配16g的swap交换分区，看看行不行。</p><p>Linux安装manjaro（gnome）或ubuntu都可以。只要能运行docker，docker-compose。</p><p>网络设置为桥接。进linux后查看虚拟机分配到的IP。</p><p>启用WSL2后安装docker windows版，不需要设置桥接，用127.0.0.1即可。</p><p>用于演示的服务程序：</p><p><a href="https://archive.org/download/gio-docker-braindead" target="_blank" rel="noreferrer">https://archive.org/download/gio-docker-braindead</a></p><p><a href="https://archive.org/download/gio-docker-braindead/3.2-3.4_srv-bins.rar" target="_blank" rel="noreferrer">3.2-3.4_srv-bins.rar</a></p><p><a href="https://archive.org/download/gio-docker-braindead/server-1.0-4.0-data.7z" target="_blank" rel="noreferrer">server-1.0-4.0-data.7z</a></p><p><a href="https://archive.org/download/gio-docker-braindead/gio-docker-braindead-mistress-v14.zip" target="_blank" rel="noreferrer">gio-docker-braindead-mistress-v14.zip</a></p><p>gio-docker-braindead-mistress-v14.zip中的3.2_dev文件夹下的内容，放到linux下的/home/test/gi目录下，</p><p>3.2-3.4_srv-bins.rar中解压出3.2_beta下的hk4e_output，里面的内容全部复制到/home/test/gi/server。</p><p>server-1.0-4.0-data.7z中解压出welink_3.2_qa.7z，其中内容放置到/home/test/gi/server/data下，合并文件夹，重复文件不要覆盖。</p><p>修改version.txt</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>{&quot;client_md5_&quot;:&quot;810a5bdaafc6dd30b1d9979215935871&quot;,&quot;client_platform_md5_&quot;:&quot;810a5bdaafc6dd30b1d9979215935871&quot;,&quot;client_silence_md5_&quot;:&quot;810a5bdaafc6dd30b1d9979215935871&quot;,&quot;client_silence_platform_md5_&quot;:&quot;810a5bdaafc6dd30b1d9979215935871&quot;,&quot;server_&quot;:683743,&quot;client_&quot;:683743,&quot;client_silence_&quot;:683743}</span></span></code></pre></div><p>修改/home/test/gi目录下的.env文件，修改OUTER_IP=为虚拟机被分配的内网IP。</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>systemctl start docker /启动docker</span></span>
<span class="line"><span>cd /home/test/gi</span></span>
<span class="line"><span>sudo sh bootstrap.sh /只需要运行一次。</span></span>
<span class="line"><span>#如果虚拟机内网IP发生改变，就删掉.bootstrap.lock文件，修改.env再运行一次bootstrap.sh</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sudo sh start.sh /之后启动用这个命令即可</span></span></code></pre></div><p>如果报RUN PIP 之类的错误，就多试几次或跨栏上网。</p><p>3.2客户端：</p><p><a href="https://mirror.tomys.top" target="_blank" rel="noreferrer">https://mirror.tomys.top</a>，如果不能下载就切换镜像源。</p><p>尽量用IDM下载，用onedrive做CDN，下载文件容易出错，IDM一般能发现错误。不清楚免费的FDM这方面效果如何。</p><p>/软件/Games/XX/</p><p>Client_REL下既客户端，3.2的OS_Client国际服客户端，客户端没有语音包，还要另外下载PC_Audio_CN。</p><p>启动器，用启动器不需要fiddler</p><p><a href="https://github.com/Grasscutters/Cultivation/releases/" target="_blank" rel="noreferrer">https://github.com/Grasscutters/Cultivation/releases/</a></p><p>启动器运行后在设置内设置游戏文件目录，之后修改IP为虚拟机的内网IP，端口号为21000。</p><p>启动！</p>`,35)]])}var s=t(a,[[`render`,o]]);export{i as __pageData,s as default};